$cats["에어컨청소"]  = @{cards=@(@{i="❄️";n="부산에어컨청소전문";t1="에어컨청소";t2="당일출동"},@{i="💨";n="벽걸이에어컨청소";t1="벽걸이에어컨";t2="냄새제거"},@{i="🏢";n="스탠드에어컨전문";t1="스탠드에어컨";t2="분해청소"},@{i="🔧";n="에어컨수리점검";t1="에어컨수리";t2="가스충전"},@{i="🌿";n="항균에어컨케어";t1="항균코팅";t2="필터교체"});s1t="❄️ 에어컨청소 · 냄새 · 필터";s1c="에어컨청소,에어컨냄새제거,에어컨필터교체,스탠드에어컨청소,벽걸이에어컨청소,천장에어컨청소";s2t="🔧 점검 · 가스충전 · 수리";s2c="에어컨가스충전,에어컨수리,에어컨점검,에어컨드레인청소,실외기청소,에어컨설치이전";q2="에어컨 청소 주기는 어떻게 되나요?";a2="필터는 2주마다 자가 청소, 내부 세척은 연 1~2회 전문 업체에 의뢰하는 것이 권장됩니다. 특히 여름 시즌 전 점검하면 냉방 효율과 위생 상태를 함께 확보할 수 있습니다.";q3="에어컨에서 곰팡이 냄새가 나요. 해결방법은?";a3="내부 열교환기에 곰팡이가 번식한 경우입니다. 시중 자가 세척제로는 완전 제거가 어렵고, 전문 분해 청소 후 항균 코팅을 하면 냄새를 근본적으로 제거할 수 있습니다.";q4="에어컨 청소 후 냉방 효율이 좋아지나요?";a4="에어컨 내부 먼지와 이물질 제거 후 평균 15~30% 냉방 효율이 향상됩니다. 전기요금 절감 효과도 기대할 수 있어 정기 청소는 비용 대비 효과가 높습니다."}
$cats["세탁기청소"]  = @{cards=@(@{i="🫧";n="부산세탁기청소전문";t1="세탁기청소";t2="통세척"},@{i="🥁";n="드럼세탁기전문";t1="드럼세탁기";t2="분해청소"},@{i="🌀";n="통돌이세탁기청소";t1="통돌이청소";t2="냄새제거"},@{i="🔧";n="건조기청소전문";t1="건조기청소";t2="필터청소"},@{i="✨";n="세탁기항균케어";t1="항균청소";t2="세탁조세척"});s1t="🫧 세탁기통세척 · 냄새제거";s1c="세탁기통세척,드럼세탁기청소,통돌이세탁기청소,세탁기냄새제거,세탁기곰팡이제거,세탁기분해청소";s2t="🔩 건조기 · 정기관리 · 필터";s2c="건조기청소,건조기필터청소,세탁기필터청소,세탁기점검,세탁기수리,세탁기설치이전";q2="세탁기 청소를 직접 해도 되나요?";a2="시판 세탁조클리너로 기본 관리는 가능하지만, 드럼통 내부 분해 청소는 전문 장비가 필요합니다. 특히 드럼세탁기는 실링 사이 곰팡이가 깊이 자리잡아 전문 분해 청소가 효과적입니다.";q3="세탁 후 옷에서 냄새가 나요. 원인은?";a3="세탁조 내부 곰팡이와 세제 찌꺼기가 원인입니다. 세탁조 청소 후에도 냄새가 지속된다면 배수 호스 막힘이나 고무 실링 오염을 점검해야 합니다.";q4="세탁기 청소 주기는 어떻게 되나요?";a4="월 1회 자가 청소(세탁조클리너 사용), 6개월~1년마다 전문 분해 청소를 권장합니다. 아이가 있는 가정이나 반려동물을 키우는 경우 3개월마다 전문 청소를 추천합니다."}
$cats["입주청소"]    = @{cards=@(@{i="🏠";n="부산입주청소전문";t1="입주청소";t2="당일출동"},@{i="📦";n="이사청소전문";t1="이사청소";t2="퇴실청소"},@{i="✨";n="신축아파트청소";t1="신축청소";t2="새집청소"},@{i="🧹";n="줄눈청소전문";t1="줄눈청소";t2="욕실청소"},@{i="🏢";n="오피스텔청소";t1="오피스텔";t2="빌라청소"});s1t="🏠 입주청소 · 이사청소 · 신축";s1c="입주청소,이사청소,신축아파트청소,전세퇴실청소,빌라청소,오피스텔청소";s2t="✨ 특수청소 · 줄눈 · 새집";s2c="줄눈청소,새집증후군청소,빌트인청소,발코니청소,베란다청소,창문청소";q2="입주청소는 이사 전에 하나요, 후에 하나요?";a2="가구 반입 전, 즉 빈 상태에서 청소하는 것이 가장 효과적입니다. 새 집이라도 시공 먼지와 이물질이 많으므로 입주 전 전문 청소가 위생 상태를 확보하는 최선의 방법입니다.";q3="입주청소 비용은 어떻게 책정되나요?";a3="보통 평수 기준으로 책정되며, 20평대는 20~30만원, 30평대는 30~40만원 선입니다. 특수청소(줄눈, 빌트인 등) 추가 시 별도 비용이 발생합니다.";q4="퇴실청소와 입주청소 차이가 있나요?";a4="퇴실청소는 기존 거주자의 생활 흔적 제거, 입주청소는 새 입주자를 위한 위생 확보가 목적입니다. 퇴실청소 후 입주청소까지 연계 의뢰하면 할인이 가능한 업체도 많습니다."}
$cats["거주청소"]    = @{cards=@(@{i="🧹";n="부산거주청소전문";t1="가정청소";t2="정기청소"},@{i="✨";n="주부대행청소";t1="가사도우미";t2="집청소"},@{i="🏠";n="원룸청소전문";t1="원룸청소";t2="1인가구"},@{i="🌿";n="친환경청소";t1="친환경";t2="황사청소"},@{i="⏰";n="정기관리청소";t1="정기계약";t2="월정액"});s1t="🧹 거주청소 · 가정청소";s1c="거주청소,가정청소대행,정기청소,집청소,원룸청소,1인가구청소";s2t="🌿 특수부위 · 주방 · 욕실";s2c="주방기름때청소,욕실청소,화장실청소,침실청소,먼지제거,바닥왁스코팅";q2="정기청소는 얼마나 자주 이용하나요?";a2="주 1회, 격주 1회, 월 1회 등 고객 필요에 따라 정기 계약이 가능합니다. 맞벌이 가정이나 1인가구에서 월 2회 정도 이용이 가장 일반적입니다.";q3="청소 시 집에 있어야 하나요?";a3="처음 방문 시에는 함께 계시는 것을 권장하지만, 이후에는 키 위탁 방식으로 진행하는 경우도 많습니다. 신뢰 기반의 정기 계약 업체라면 부재 중 청소도 안전하게 진행됩니다.";q4="청소 후 만족스럽지 않으면 어떻게 하나요?";a4="대부분의 전문 업체는 당일 재청소 또는 환불 보장 정책을 운영합니다. 계약 전 A/S 정책을 확인하고, 정기 계약 시 첫 회 청소 후 만족도를 평가해보세요."}
$cats["상가청소"]    = @{cards=@(@{i="🏢";n="부산상가청소전문";t1="상가청소";t2="당일출동"},@{i="🍽️";n="식당주방청소";t1="식당청소";t2="후드청소"},@{i="💼";n="사무실청소전문";t1="사무실청소";t2="빌딩청소"},@{i="🔨";n="폐업철거청소";t1="폐업청소";t2="공사후청소"},@{i="🌙";n="야간청소전문";t1="야간청소";t2="새벽청소"});s1t="🏢 상가 · 사무실 · 매장 청소";s1c="상가청소,사무실청소,매장청소,식당청소,카페청소,학원청소";s2t="🔨 폐업 · 공사후 · 특수청소";s2c="폐업청소,공사후청소,철거후청소,기름때청소,후드청소,바닥코팅";q2="상가청소와 가정청소의 차이점은?";a2="상가청소는 영업 장소의 특성에 맞는 전문 장비와 약품이 필요합니다. 식당은 기름때·음식물 잔여물, 사무실은 전자기기 주변 먼지 처리 등 각 업종별 맞춤 청소가 중요합니다.";q3="영업 중에 청소가 가능한가요?";a3="대부분의 업체가 영업 전후 또는 휴무일 청소 서비스를 제공합니다. 야간·새벽 청소팀이 있는 업체에 의뢰하면 영업에 지장 없이 청소가 가능합니다.";q4="폐업 청소는 어떤 범위까지 포함되나요?";a4="기본 청소부터 집기 폐기, 인테리어 철거 후 청소까지 다양한 범위로 진행됩니다. 업체마다 제공 범위가 다르므로 견적 시 포함 항목을 명확히 확인하세요."}
$cats["인테리어"]    = @{cards=@(@{i="🏠";n="부산인테리어전문";t1="아파트인테리어";t2="리모델링"},@{i="🎨";n="경남리모델링마스터";t1="전체리모델링";t2="설계시공"},@{i="📐";n="인테리어설계";t1="3D설계";t2="견적"},@{i="🛋️";n="프리미엄인테리어";t1="고급인테리어";t2="맞춤시공"},@{i="✨";n="인테리어마스터";t1="빌라인테리어";t2="오피스텔"});s1t="🏠 인테리어 · 리모델링 · 시공";s1c="아파트인테리어,빌라리모델링,사무실인테리어,인테리어견적,신혼인테리어,풀패키지리모델링";s2t="🎨 설계 · 철거 · 마감";s2c="인테리어설계,3D시뮬레이션,철거공사,도배장판,조명공사,가구배치";q2="아파트 리모델링 비용은 얼마나 되나요?";a2="아파트 리모델링 비용은 평수와 공사 범위에 따라 다릅니다. 20평대 기준 1,000~2,500만원, 30평대는 1,500~3,500만원 선이 일반적입니다. 욕실·주방·전체 리모델링 범위에 따라 견적이 달라지므로 현장 방문 견적을 통해 정확한 비용을 확인하세요.";q3="인테리어 공사 기간은 얼마나 걸리나요?";a3="부분 공사(욕실, 주방)는 3~7일, 전체 리모델링은 2~6주 정도 소요됩니다. 자재 선택과 시공 범위에 따라 달라지므로 착공 전 일정을 정확히 협의하세요.";q4="인테리어 업체 선정 시 가장 중요한 것은?";a4="포트폴리오, 시공 사례, 계약서 내용을 꼼꼼히 확인하세요. 구두 약속보다 계약서에 공사 범위, 금액, 완료일을 명시하고, 하자 보수 기간(통상 1~2년)도 확인하는 것이 중요합니다."}
$cats["도배"]        = @{cards=@(@{i="🖼️";n="부산도배전문";t1="합지도배";t2="실크도배"},@{i="🏠";n="아파트도배전문";t1="아파트도배";t2="원룸도배"},@{i="📋";n="장판교체전문";t1="장판교체";t2="강화마루"},@{i="🎨";n="벽지시공전문";t1="포인트벽지";t2="수입벽지"},@{i="🔧";n="도배장판종합";t1="도배장판";t2="동시시공"});s1t="🖼️ 도배 · 벽지 · 장판";s1c="합지도배,실크도배,포인트벽지,수입벽지,장판교체,데코타일";s2t="🏠 공간별 · 재시공 · 관리";s2c="아파트도배,원룸도배,상가도배,도배재시공,곰팡이벽지교체,방음벽지";q2="합지도배와 실크도배 중 어떤 게 좋나요?";a2="합지는 저렴하고 시공이 간편하지만 내구성이 낮습니다. 실크(PVC)는 내구성·세척성이 뛰어나 주방, 욕실 인접 공간에 적합합니다. 거실·침실은 합지, 주방·복도는 실크를 많이 선택합니다.";q3="도배 후 냄새가 나요. 언제 없어지나요?";a3="도배 풀의 냄새는 보통 3~7일이면 자연 환기로 사라집니다. 환기를 충분히 하고, 빠른 제거를 원한다면 숯이나 식물을 배치하는 방법도 효과적입니다.";q4="도배 셀프 시공이 가능한가요?";a4="합지도배는 셀프 시공이 가능하지만, 실크벽지는 전문 기술이 필요합니다. 모서리 처리와 패턴 맞춤이 어려우므로 전문 업체에 의뢰하면 깔끔한 마감을 기대할 수 있습니다."}
$cats["타일"]        = @{cards=@(@{i="🏗️";n="부산타일전문";t1="타일시공";t2="욕실타일"},@{i="🍽️";n="주방타일전문";t1="주방타일";t2="타일교체"},@{i="🏠";n="현관타일전문";t1="현관타일";t2="거실타일"},@{i="🔨";n="타일철거재시공";t1="타일철거";t2="재시공"},@{i="✨";n="줄눈전문";t1="줄눈시공";t2="줄눈청소"});s1t="🏗️ 타일시공 · 욕실 · 주방";s1c="욕실타일교체,주방타일시공,현관타일,거실타일,포세린타일,대리석타일";s2t="🔨 철거 · 재시공 · 줄눈";s2c="타일철거재시공,깨진타일수리,줄눈시공,줄눈청소,방수타일,논슬립타일";q2="타일 시공 시 어떤 타일을 선택해야 하나요?";a2="욕실은 방수·논슬립 처리된 타일, 주방은 기름때에 강한 유광 타일, 거실은 포세린 또는 대형 타일이 인기입니다. 공간 크기와 분위기에 맞는 색상과 패턴을 선택하세요.";q3="타일 교체 없이 줄눈만 새로 할 수 있나요?";a3="줄눈 재시공은 기존 줄눈을 제거하고 새 줄눈재를 채우는 방식으로 진행됩니다. 타일을 교체하지 않아도 욕실 분위기를 새로 바꿀 수 있고, 방수 성능도 회복됩니다.";q4="타일 사이로 물이 스며드는 것 같아요. 어떻게 하나요?";a4="줄눈이 갈라지거나 타일 뒤 방수층이 손상된 경우입니다. 줄눈 재시공으로 초기에 막으면 비용이 적지만, 방수층까지 손상되었다면 타일 철거 후 방수 재시공이 필요합니다."}
$cats["욕실리모델링"] = @{cards=@(@{i="🛁";n="부산욕실리모델링";t1="욕실공사";t2="당일견적"},@{i="🚿";n="샤워부스전문";t1="샤워부스설치";t2="욕조교체"},@{i="🔧";n="욕실설비전문";t1="세면대교체";t2="양변기교체"},@{i="🏗️";n="욕실타일전문";t1="욕실타일";t2="방수공사"},@{i="✨";n="욕실인테리어";t1="욕실개조";t2="전체시공"});s1t="🛁 욕실리모델링 · 공사 · 개조";s1c="욕실리모델링,욕실공사,욕실개조,욕조교체,샤워부스설치,욕실인테리어";s2t="🔧 설비 · 방수 · 타일";s2c="세면대교체,양변기교체,수전교체,욕실방수,욕실타일교체,욕실환풍기교체";q2="욕실 리모델링 비용은 얼마나 드나요?";a2="기본형(설비 교체 중심) 150~250만원, 중급형(타일+설비) 300~500만원, 고급형(전체 시공) 500만원 이상입니다. 욕실 크기와 자재에 따라 달라지므로 현장 견적을 통해 확인하세요.";q3="욕실 리모델링 기간은 얼마나 걸리나요?";a3="기본 설비 교체는 1~2일, 타일+설비 중간 공사는 3~5일, 전체 철거 후 재시공은 5~10일이 소요됩니다. 방수 양생 기간(2~3일)이 포함되므로 사전 일정 조율이 필요합니다.";q4="욕실 리모델링 시 꼭 확인해야 할 사항은?";a4="방수 시공 여부, 환기 개선 계획, 기존 배관 상태 확인이 중요합니다. 저렴한 견적이라도 방수를 생략하면 추후 누수로 더 큰 비용이 발생할 수 있습니다."}
$cats["마루"]        = @{cards=@(@{i="🪵";n="부산마루시공전문";t1="강마루";t2="원목마루"},@{i="🏠";n="강화마루전문";t1="강화마루";t2="합판마루"},@{i="📋";n="장판교체전문";t1="장판시공";t2="PVC장판"},@{i="🔧";n="바닥재교체";t1="바닥재교체";t2="셀프시공"},@{i="✨";n="마루광택왁스";t1="마루왁스";t2="바닥광택"});s1t="🪵 마루 · 바닥재 · 장판";s1c="강마루시공,원목마루,강화마루,합판마루,장판시공,데코타일";s2t="🔧 교체 · 보수 · 광택";s2c="마루교체,바닥재교체,마루뜯기,마루보수,바닥왁스코팅,마루이음새수리";q2="강마루, 원목마루, 강화마루 중 어떤 게 좋나요?";a2="원목마루는 자연미가 뛰어나지만 관리가 까다롭습니다. 강마루는 내구성과 방수성이 뛰어나 실용적입니다. 강화마루는 가격이 저렴하고 셀프 시공이 가능하지만 습기에 약합니다.";q3="마루 시공 후 삐걱거리는 소리가 나요. 해결방법은?";a3="바닥 평탄 작업 부족이나 마루 이음새 문제로 발생합니다. 심하지 않으면 이음새 부분에 전용 왁스를 채워 개선할 수 있고, 심한 경우 해당 부분 재시공이 필요합니다.";q4="마루 표면 스크래치는 어떻게 수리하나요?";a4="가벼운 스크래치는 마루 전용 보수제나 마커펜으로 메울 수 있습니다. 깊은 스크래치는 해당 마루판을 교체하는 것이 효과적입니다. 정기적인 왁스 코팅으로 스크래치를 예방하세요."}
$cats["페인트"]      = @{cards=@(@{i="🎨";n="부산페인트전문";t1="내벽페인트";t2="외벽도장"},@{i="🏢";n="외벽도색전문";t1="외벽도색";t2="방수페인트"},@{i="🖌️";n="인테리어페인트";t1="셀프페인트";t2="친환경페인트"},@{i="🏗️";n="상업시설도장";t1="상가도색";t2="철제도장"},@{i="🏠";n="아파트도색전문";t1="아파트도색";t2="단지도장"});s1t="🎨 페인트 · 도색 · 도장";s1c="내벽페인트시공,외벽도장,방수페인트,에폭시코팅,친환경페인트,인테리어도색";s2t="🏗️ 외벽 · 철제 · 특수";s2c="외벽도색,철제구조물도장,주차장라인도장,바닥에폭시,내화도료,방청도장";q2="페인트 도색 주기는 어떻게 되나요?";a2="내벽은 5~10년, 외벽은 8~15년마다 재도색이 일반적입니다. 자외선과 비에 노출되는 외벽은 더 자주 점검이 필요하며, 크랙이나 박리 현상이 보이면 즉시 재도색하세요.";q3="친환경 페인트와 일반 페인트 차이는?";a3="친환경 페인트는 VOC(휘발성 유기화합물) 함량이 낮아 실내 공기질에 유리합니다. 가격은 다소 높지만 어린이방, 침실 등 밀폐 공간에는 친환경 제품을 권장합니다.";q4="페인트 도색 전 준비사항은?";a4="기존 도막 상태 점검, 크랙·박리 부위 퍼티 처리, 표면 이물질 제거가 선행되어야 합니다. 준비 작업 없이 바로 도색하면 도막 수명이 단축되고 박리가 빠르게 진행됩니다."}
$cats["창문교체"]    = @{cards=@(@{i="🪟";n="부산창문교체전문";t1="창문교체";t2="샷시교체"},@{i="🔇";n="방음창전문";t1="방음창";t2="이중창"},@{i="❄️";n="단열창전문";t1="단열창";t2="에너지효율"},@{i="🔒";n="이중창설치";t1="이중창설치";t2="시스템창호"},@{i="🔧";n="창문수리전문";t1="창문수리";t2="베란다샷시"});s1t="🪟 창문교체 · 샷시 · 시스템창호";s1c="창문교체,샷시교체,이중창설치,단열창,방음창,시스템창호";s2t="🔧 수리 · 베란다 · 방범";s2c="창문수리,창틀교체,베란다샷시,방범창,창문방풍,유리교체";q2="이중창과 단창 중 어떤 게 좋나요?";a2="이중창은 단열·방음 성능이 월등히 뛰어나 에너지 절약과 소음 차단에 효과적입니다. 초기 비용은 높지만 냉난방비 절감 효과로 장기적으로 경제적입니다. 소음이 심한 지역이라면 이중창을 강력 추천합니다.";q3="창문 교체 후 단열 효과가 바로 느껴지나요?";a3="네, 시공 당일부터 효과를 체감할 수 있습니다. 특히 겨울철에는 외풍이 현저히 줄어들고, 여름철에는 냉방 효율이 향상되어 전기 요금 절감을 기대할 수 있습니다.";q4="창문 교체 시공 기간은 얼마나 걸리나요?";a4="가정용 창문 1~2개 교체는 2~4시간, 전체 창호 교체는 하루 내에 완료됩니다. 시공 후 실리콘 양생까지 고려하면 당일 기본 사용은 가능하지만 완전 양생은 24시간이 필요합니다."}
$cats["주방리모델링"] = @{cards=@(@{i="🍳";n="부산주방리모델링";t1="주방공사";t2="싱크대교체"},@{i="🪑";n="싱크대전문";t1="싱크대설치";t2="주방가구"},@{i="🏗️";n="주방타일전문";t1="주방타일";t2="백스플래시"},@{i="💡";n="주방조명전문";t1="주방조명";t2="LED조명"},@{i="✨";n="주방인테리어";t1="주방인테리어";t2="주방개조"});s1t="🍳 주방리모델링 · 싱크대 · 교체";s1c="주방리모델링,주방인테리어,싱크대교체,주방타일,주방개조,주방공사";s2t="🔧 가구 · 조명 · 설비";s2c="주방가구교체,주방조명교체,주방환풍기교체,빌트인가전설치,상부장교체,하부장교체";q2="주방 리모델링 비용은 얼마나 드나요?";a2="싱크대 교체만은 200~500만원, 타일+싱크대 중간 공사는 400~800만원, 전체 주방 리모델링은 600~1,500만원 선입니다. 자재와 가전 포함 여부에 따라 달라집니다.";q3="싱크대 교체 기간은 얼마나 걸리나요?";a3="싱크대 단순 교체는 1~2일, 타일 포함 공사는 3~5일이 소요됩니다. 맞춤 제작 싱크대는 제작 기간(2~4주)이 별도로 필요하므로 미리 계획하세요.";q4="오래된 주방 수납장만 교체할 수 있나요?";a4="상부장·하부장 등 부분 교체도 가능합니다. 기존 싱크대와 색상·디자인을 맞추는 것이 중요하므로 전문 업체의 현장 방문 상담 후 진행을 권장합니다."}

# ── 처리 함수
function Make-Cards($cardList, $loc, $url) {
  $html = ""
  foreach ($cd in $cardList) {
    $html += "    <div class=""card""><div class=""card-thumb"">$($cd.i)</div><div class=""card-body""><div class=""card-name"">$($cd.n)</div><div class=""card-tags""><span class=""tag hot"">$($cd.t1)</span><span class=""tag"">$($cd.t2)</span></div><div class=""card-addr"">📍 $loc</div><a class=""card-link"" href=""$url"" target=""_blank"" referrerpolicy=""unsafe-url"">업체 위치 보기</a></div></div>`r`n"
  }
  return $html
}

# ── 카테고리 폴더 처리
foreach ($folder in $cats.Keys) {
  $catDir = Join-Path $siteRoot $folder
  if (-not (Test-Path $catDir)) { continue }
  $d = $cats[$folder]
  $pageCnt = 0

  foreach ($file in (Get-ChildItem $catDir -Recurse -Filter "*.html")) {
    $c = [IO.File]::ReadAllText($file.FullName, [Text.Encoding]::UTF8)

    # 위치 추출
    $area = ""
    if ($c -match '(?s)class="hero-title">[^<]+<br>\s*([^\r\n<]+?)\s*<em>') { $area = $matches[1].Trim() }
    if (-not $area -and $c -match '<title>([^|<]+)') {
      $area = $matches[1].Trim() -replace '\s+\S+$', ''
    }
    if (-not $area) { $errors++; continue }

    # ① 헤더 로고
    $c = $c.Replace("즐거운 <span>탱이네</span>", "마케팅 플레이스 <span>블로그 홍보 문의</span>")
    $c = $c.Replace("즐거운 탱이네", "마케팅 플레이스 블로그 홍보 문의")

    # ② 인트로 박스 삭제
    $c = [regex]::Replace($c, '(?s)<p class="intro-box"[^>]*>.*?</p>', '')

    # ③ 비-스폰서 카드 교체
    $newCards = Make-Cards $d.cards $area $coupangUrl
    $c = [regex]::Replace($c, '(?s)(<div class="card">\s*<div class="card-thumb">.*?</div>\s*</div>\s*)+', $newCards)

    # ④ 서비스 키워드 섹션 교체
    $chips1 = ($d.s1c -split ",") | ForEach-Object { "<span class=""kwchip"">$_</span>" }
    $chips2 = ($d.s2c -split ",") | ForEach-Object { "<span class=""kwchip"">$_</span>" }
    $newSvc = "  <!-- 서비스 키워드 -->`r`n  <h2 class=""section-title"">$area $folder 서비스 키워드</h2>`r`n  <div class=""service-block""><h3>$($d.s1t)</h3><div class=""keyword-list"">$($chips1 -join '')</div></div>`r`n  <div class=""service-block""><h3>$($d.s2t)</h3><div class=""keyword-list"">$($chips2 -join '')</div></div>`r`n"
    $c = [regex]::Replace($c, '(?s)<!-- 서비스 키워드 -->.*?(?=\s*<!-- 지도|\s*<h2 class="section-title">.*?지도)', $newSvc)

    # ⑤ FAQ 교체
    $newFaq = "  <!-- FAQ -->`r`n  <h2 class=""section-title"">자주 묻는 질문</h2>`r`n  <div class=""faq-list"">`r`n    <details class=""faq""><summary class=""faq-q"">$area $folder 업체를 빠르게 찾으려면?</summary><div class=""faq-a"">$area 인근 $folder 관련 업체들을 모아 안내해 드리는 페이지입니다. 본문 업체 정보와 지도 링크를 통해 확인하실 수 있습니다.</div></details>`r`n    <details class=""faq""><summary class=""faq-q"">$($d.q2)</summary><div class=""faq-a"">$($d.a2)</div></details>`r`n    <details class=""faq""><summary class=""faq-q"">$($d.q3)</summary><div class=""faq-a"">$($d.a3)</div></details>`r`n    <details class=""faq""><summary class=""faq-q"">$($d.q4)</summary><div class=""faq-a"">$($d.a4)</div></details>`r`n  </div>`r`n"
    $c = [regex]::Replace($c, '(?s)<!-- FAQ -->.*?(?=\s*<!-- 페이지네이션|\s*<nav class="pagination")', $newFaq)

    [IO.File]::WriteAllText($file.FullName, $c, (New-Object Text.UTF8Encoding $false))
    $processed++; $pageCnt++
  }
  Write-Host "[$folder] $pageCnt 페이지"
}

Write-Host ""
Write-Host "완료: $processed 페이지 | 오류: $errors"
